mapper.select:
select FEE_CODE , FEE_TYPE , START_DT, END_DT, CLASS_NO, KOR_NM, ENG_NM, DIV_TYPE, SURG_YN, CLN_PRICE, HOS_PRICE, DNT_PRICE, PBL_PRICE , MID_PRICE , ORH_PRICE , RLT_VALUE , COPAY_50 , COPAY_80 , COPAY_90 , DUP_YN , CALC_NM , SEC_MAJ , SEC_MIN , SUB_CAT From TBL_SUGA_MST where 1=1
AND (KOR_NM LIKE CONCAT(#{kor_nm},'%') OR FEE_CODE LIKE CONCAT(#{kor_nm},'%') )
Order by FEE_CODE , START_DT LIMIT #{pageSize} OFFSET #{pageIndex}


SELECT 'Y'
  FROM TBL_CODE_MST
 WHERE CODE_cd = #{code_cd}

SELECT CODE_GB, CODE_CD, SUB_CODE, RTRIM(SUB_CODE_NM) SUB_CODE_NM, DATE_FORMAT(START_DT, '%Y-%m-%d') START_DT , DATE_FORMAT(END_DT, '%Y-%m-%d') END_DT , IFNULL(USE_YN,'') USE_YN , IFNull(SORT,'1') SORT , REG_DTTM , REG_USER , REG_IP , UPD_DTTM , UPD_USER , UPD_IP FROM TBL_CODE_DTL WHERE CODE_CD = #{code_cd}
AND ( SUB_CODE LIKE CONCAT('%',#{sub_code},'%') )
ORDER BY CODE_CD , CODE_GB , SUB_CODE

SELECT A.CODE_GB, B.SUB_CODE_NM AS CODE_GBNM , A.CODE_CD, A.SUB_CODE , A.SUB_CODE_NM , A.START_DT, A.END_DT, A.USE_YN, IFNULL(A.PROP_1,'') AS PROP_1 , IFNULL(A.PROP_5,'') AS PROP_5 , COALESCE(A.SORT, '1') AS SORT FROM TBL_CODE_DTL A INNER JOIN TBL_CODE_DTL B ON B.CODE_CD = 'CODE_GB' AND B.SUB_CODE = A.CODE_GB WHERE A.CODE_CD = #{code_cd}
AND A.SUB_CODE = #{sub_code}
AND A.SUB_CODE_NM LIKE CONCAT('%', #{sub_code_nm}, '%')
AND A.USE_YN = #{use_yn}
AND A.CODE_GB = #{code_gb}
ORDER BY A.SORT, A.SUB_CODE, A.START_DT


SELECT 'Y'
  FROM TBL_CODE_DTL
 WHERE CODE_CD   = #{code_cd}
   AND SUB_CODE  = #{sub_code}
   AND CODE_GB   = #{code_gb}

mapper.update:

UPDATE TBL_CODE_DTL
   SET USE_YN     = 'N'
       SORT       =  #{sort},
       END_DT     =  DATE_FORMAT(NOW(), '%Y%m%d'), 
       UPD_DTTM   =  now() ,
       UPD_USER   = 'admin'
 WHERE CODE_CD    = #{code_cd} 
   AND SUB_CODE   = #{sub_code}
   AND CODE_GB    = #{code_gb}

mapper.delete:

DELETE FROM TBL_USER_MST
WHERE _CD = #{hosp_cd}
  AND USER_ID = #{user_id}
  And START_DT = REPLACE(#{start_dt} , '-', '')

mapper.select:

	  SELECT PASS_WD , 
             USER_ID  
	    FROM TBL_USER_MST
       Where 1=1
		   And USER_NM = #{user_nm}
		   And EMAIL   = #{email}

mapper.update:

	  UPDATE TBL_USER_MST
	     SET PASS_WD  = #{enc_user_pwd}
       Where 1=1
		   And HOSP_UUID = #{hosp_uuid}
		   And USER_ID = #{user_id}


	   ORDER BY START_DT DESC
	   LIMIT 1

mapper.delete:

DELETE FROM TBL_HOSP_MST 
WHERE 1=1 
  AND HOSP_CD  = #{hosp_cd}

mapper.update:

UPDATE TBL_HOSP_DTL
SET WARDCNT   = #{wardcnt},
    ICUCNT    = #{icucnt},
    ERCNT     = #{ercnt},
    DOCCNT    = #{doccnt},
    UPD_DTTM  = NOW(),
    UPD_USER  = #{upd_user},
    UPD_IP    = #{upd_ip}
WHERE HOSP_CD  = #{hosp_cd2}
  AND START_YM = #{start_ym}

mapper.delete:

DELETE FROM TBL_HOSP_DTL
WHERE HOSP_CD  = #{hosp_cd2}
  AND START_YM = #{start_ym}

mapper.select:
select DIAG_CODE, START_DT, KOR_DIAG_NAME, ENG_DIAG_NAME, GENDER_TYPE, INFECT_TYPE, DIAG_TYPE, ICD10_CODE, END_DT, MAX_AGE, MIN_AGE, VCODE, DESC_INFO, REG_DTTM, REG_USER, REG_IP, UPD_DTTM, UPD_USER, UPD_IP From TBL_DISE_CODE where 1=1
AND (KOR_DIAG_NAME LIKE CONCAT('%',#{kor_diag_name},'%') OR DIAG_CODE LIKE CONCAT('%',#{kor_diag_name},'%') )
Order by DIAG_CODE , START_DT LIMIT #{pageSize} OFFSET #{pageIndex}

mapper.delete:

DELETE FROM TBL_DISE_CODE
WHERE DIAG_CODE  = #{diag_code}
  AND START_DT   = REPLACE(#{start_dt},'-','')

mapper.select:
SELECT A.SAMVER, A.TBLINFO, B.SUB_CODE_NM, A.VERSION, A.SEQ, A.SORT_SEQ, A.ITEM_NM, A.START_POS, A.END_POS, A.DATA_TYPE, IFNULL(A.DECIMAL_POS, '') AS DECIMAL_POS, A.DATAPROC_YN, IFNULL(A.DB_COLNM, '') AS DB_COLNM, IFNULL(A.LAST_YN, 'N') AS LAST_YN FROM TBL_SAMFVER_MST A INNER JOIN TBL_CODE_DTL B ON B.CODE_CD = 'TBLINFO' AND B.SUB_CODE = A.TBLINFO WHERE 1 = 1
AND (A.SAMVER LIKE CONCAT('%', #{samver}, '%') or A.VERSION = #{version} or (A.SAMVER BETWEEN #{samver} AND #{prop_1}))
AND A.TBLINFO = #{tblinfo}
AND A.DATAPROC_YN = #{dataproc_yn}
ORDER BY A.VERSION, A.SAMVER, B.SORT, A.TBLINFO,A.SEQ


SELECT TOP(1) 'Y'
  FROM dbo.TBL_CODE_DTL A
 WHERE A.CODE_CODE = #{code_cd}
   AND A.CODE_GB   = #{code_gb}  
   AND A.SUB_CODE  = #{sub_code}


SELECT 'Y'
  FROM TBL_SAMFVER_MST A 
 WHERE A.SAMVER    = #{samver}
   AND A.VERSION   = #{version} 
   AND A.TBLINFO   = #{tblinfo}
   AND A.DB_COLNM   = UPPER(#{db_coln})

mapper.update:

UPDATE TBL_SAMFVER_MST
   SET ITEM_NM      = #{item_nm}
     , SORTSEQ      = #{sort_seq}
     , STARTPOS     = #{start_pos}
     , ENDPOS       = #{end_pos}
     , DATA_TYPE    = #{data_type}
     , DECIMAL_POS  = #{decimal_pos}
     , DATAPROC_YN  = #{dataproc_yn}
     , DB_COLNM     = UPPER(#{db_colnm}) 
     , LAST_YN      = #{last_yn}
  WHERE SAMVER      = #{samver}
    AND VERSION     = #{version}
    AND SEQ         = #{seq}

mapper.delete:

DELETE FROM TBL_WEVALUE_MST
WHERE CATE_CODE = #{cate_code} 
  AND ORDER_SEQ = #{order_seq} 
  AND START_DT  = replace(#{start_dt},'-','')
